def _parse(pattern):
    pos = [0]
    n = len(pattern)

    def peek():
        return pattern[pos[0]] if pos[0] < n else None

    def parse_alt():
        branches = [parse_seq()]
        while peek() == '|':
            pos[0] += 1
            branches.append(parse_seq())
        if len(branches) == 1:
            return branches[0]
        return ('alt', branches)

    def parse_seq():
        items = []
        while peek() is not None and peek() not in '|)':
            items.append(parse_quant())
        return ('seq', items)

    def parse_quant():
        atom = parse_atom()
        q = peek()
        if q == '*':
            pos[0] += 1
            return ('repeat', atom, 0, None)
        if q == '+':
            pos[0] += 1
            return ('repeat', atom, 1, None)
        if q == '?':
            pos[0] += 1
            return ('repeat', atom, 0, 1)
        return atom

    def parse_atom():
        c = pattern[pos[0]]
        if c == '(':
            pos[0] += 1
            node = parse_alt()
            pos[0] += 1
            return node
        if c == '[':
            return parse_class()
        if c == '.':
            pos[0] += 1
            return ('any',)
        pos[0] += 1
        return ('lit', c)

    def parse_class():
        pos[0] += 1
        negate = False
        if peek() == '^':
            negate = True
            pos[0] += 1
        chars = set()
        ranges = []
        while peek() != ']':
            c = pattern[pos[0]]
            if pos[0] + 2 < n and pattern[pos[0] + 1] == '-' and pattern[pos[0] + 2] != ']':
                ranges.append((c, pattern[pos[0] + 2]))
                pos[0] += 3
            else:
                chars.add(c)
                pos[0] += 1
        pos[0] += 1
        return ('class', negate, chars, ranges)

    return parse_alt()


def _match_node(node, text, pos, cont):
    kind = node[0]
    n = len(text)

    if kind == 'lit':
        if pos < n and text[pos] == node[1]:
            return cont(pos + 1)
        return False

    if kind == 'any':
        if pos < n:
            return cont(pos + 1)
        return False

    if kind == 'class':
        _, negate, chars, ranges = node
        if pos < n:
            ch = text[pos]
            inside = ch in chars or any(a <= ch <= b for a, b in ranges)
            if inside != negate:
                return cont(pos + 1)
        return False

    if kind == 'seq':
        items = node[1]

        def seq_match(i, p):
            if i == len(items):
                return cont(p)
            return _match_node(items[i], text, p, lambda np: seq_match(i + 1, np))

        return seq_match(0, pos)

    if kind == 'alt':
        for branch in node[1]:
            if _match_node(branch, text, pos, cont):
                return True
        return False

    if kind == 'repeat':
        atom, minr, maxr = node[1], node[2], node[3]

        def helper(p, count):
            if maxr is None or count < maxr:
                def try_more(np):
                    if np == p:
                        if count + 1 >= minr:
                            return cont(np)
                        return False
                    return helper(np, count + 1)

                if _match_node(atom, text, p, try_more):
                    return True
            if count >= minr:
                return cont(p)
            return False

        return helper(pos, 0)

    return False


def match(pattern: str, text: str) -> bool:
    ast = _parse(pattern)
    return _match_node(ast, text, 0, lambda p: p == len(text))
